/// <summary>
/// Secure value wrapper that prevents memory manipulation/scanning.
/// Stores values in an obfuscated form with integrity checking.
/// </summary>
[Serializable]
public struct SecureInt
{
    private int _obfuscatedValue;
    private int _key;
    private int _checksum;

    private void Initialize()
    {
        if (_key == 0)
        {
            _key = UnityEngine.Random.Range(int.MinValue / 2, int.MaxValue / 2);
            if (_key == 0) _key = 12345;
        }
    }

    public int Value
    {
        get
        {
            int real = _obfuscatedValue ^ _key;
            int expectedChecksum = ComputeChecksum(real);
            if (_checksum != expectedChecksum && _checksum != 0)
            {
                Debug.LogError("[SECURITY] Memory tampering detected on SecureInt!");
                OnTamperDetected?.Invoke();
                return 0;
            }
            return real;
        }
        set
        {
            Initialize();
            _obfuscatedValue = value ^ _key;
            _checksum = ComputeChecksum(value);
        }
    }

    private int ComputeChecksum(int val)
    {
        return (val * 31 + _key * 17) ^ 0x5A5A5A5A;
    }

    public static implicit operator int(SecureInt s) => s.Value;

    public static event Action OnTamperDetected;

    public override string ToString() => Value.ToString();
}

