/// <summary>
/// Secure PlayerPrefs that uses HMAC to detect tampering of saved data.
/// </summary>
public static class SecurePlayerPrefs
{
    private static readonly string _hmacKey = SystemInfo.deviceUniqueIdentifier + "_GameSalt_2024";

    public static void SetInt(string key, int value)
    {
        PlayerPrefs.SetInt(key, value);
        PlayerPrefs.SetString(key + "_hash", ComputeHMAC(key + ":" + value));
        PlayerPrefs.Save();
    }

    public static int GetInt(string key, int defaultValue = 0)
    {
        if (!PlayerPrefs.HasKey(key)) return defaultValue;

        int value = PlayerPrefs.GetInt(key, defaultValue);
        string storedHash = PlayerPrefs.GetString(key + "_hash", "");
        string expectedHash = ComputeHMAC(key + ":" + value);

        if (storedHash != expectedHash)
        {
            Debug.LogError($"[SECURITY] PlayerPrefs tampering detected for key: {key}");
            PlayerPrefs.DeleteKey(key);
            PlayerPrefs.DeleteKey(key + "_hash");
            return defaultValue;
        }

        return value;
    }

    public static void SetFloat(string key, float value)
    {
        PlayerPrefs.SetFloat(key, value);
        PlayerPrefs.SetString(key + "_hash", ComputeHMAC(key + ":" + value));
        PlayerPrefs.Save();
    }

    public static float GetFloat(string key, float defaultValue = 0f)
    {
        if (!PlayerPrefs.HasKey(key)) return defaultValue;

        float value = PlayerPrefs.GetFloat(key, defaultValue);
        string storedHash = PlayerPrefs.GetString(key + "_hash", "");
        string expectedHash = ComputeHMAC(key + ":" + value);

        if (storedHash != expectedHash)
        {
            Debug.LogError($"[SECURITY] PlayerPrefs tampering detected for key: {key}");
            PlayerPrefs.DeleteKey(key);
            PlayerPrefs.DeleteKey(key + "_hash");
            return defaultValue;
        }

        return value;
    }

    public static void SetString(string key, string value)
    {
        PlayerPrefs.SetString(key, value);
        PlayerPrefs.SetString(key + "_hash", ComputeHMAC(key + ":" + value));
        PlayerPrefs.Save();
    }

    public static string GetString(string key, string defaultValue = "")
    {
        if (!PlayerPrefs.HasKey(key)) return defaultValue;

        string value = PlayerPrefs.GetString(key, defaultValue);
        string storedHash = PlayerPrefs.GetString(key + "_hash", "");
        string expectedHash = ComputeHMAC(key + ":" + value);

        if (storedHash != expectedHash)
        {
            Debug.LogError($"[SECURITY] PlayerPrefs tampering detected for key: {key}");
            PlayerPrefs.DeleteKey(key);
            PlayerPrefs.DeleteKey(key + "_hash");
            return defaultValue;
        }

        return value;
    }

    private static string ComputeHMAC(string data)
    {
        using (var hmac = new HMACSHA256(Encoding.UTF8.GetBytes(_hmacKey)))
        {
            byte[] hash = hmac.ComputeHash(Encoding.UTF8.GetBytes(data));
            return Convert.ToBase64String(hash);
        }
    }
}

