/// <summary>
/// Manages player stats with anti-tampering protection.
/// All public-facing values go through secure wrappers.
/// </summary>
public class PlayerStats : MonoBehaviour
{
    public static PlayerStats Instance { get; private set; }

    // Public accessors (read-only properties backed by secure storage)
    public int Health => _health.Value;
    public int MaxHealth => _maxHealth.Value;
    public int Currency => _currency.Value;
    public int BaseDamage => _baseDamage.Value;
    public float DamageMultiplier => _damageMultiplier.Value;
    public int ArmorRating => _armorRating.Value;
    public int Level => _level.Value;

    // Secure backing fields
    private SecureInt _health;
    private SecureInt _maxHealth;
    private SecureInt _currency;
    private SecureInt _baseDamage;
    private SecureFloat _damageMultiplier;
    private SecureInt _armorRating;
    private SecureInt _level;

    // Redundant shadow copies for cross-validation
    private SecureInt _healthShadow;
    private SecureInt _currencyShadow;

    // Integrity check timer
    private float _integrityCheckInterval = 2f;
    private float _integrityCheckTimer;

    // Events
    public event Action<int, int> OnHealthChanged; // current, max
    public event Action<int> OnCurrencyChanged;
    public event Action OnPlayerDied;
    public event Action OnTamperingDetected;

    [Header("Starting Stats")]
    [SerializeField] private int startingHealth = 100;
    [SerializeField] private int startingCurrency = 0;
    [SerializeField] private int startingBaseDamage = 10;
    [SerializeField] private float startingDamageMultiplier = 1.0f;
    [SerializeField] private int startingArmorRating = 0;

    private bool _isDead;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }
        Instance = this;
        DontDestroyOnLoad(gameObject);

        SecureInt.OnTamperDetected += HandleTamperDetected;
        SecureFloat.OnTamperDetected += HandleTamperDetected;

        LoadOrInitializeStats();
    }

    private void OnDestroy()
    {
        SecureInt.OnTamperDetected -= HandleTamperDetected;
        SecureFloat.OnTamperDetected -= HandleTamperDetected;
    }

    private void Update()
    {
        _integrityCheckTimer += Time.deltaTime;
        if (_integrityCheckTimer >= _integrityCheckInterval)
        {
            _integrityCheckTimer = 0f;
            PerformIntegrityCheck();
        }
    }

    private void LoadOrInitializeStats()
    {
        if (SecurePlayerPrefs.GetInt("HasSaveData", 0) == 1)
        {
            _maxHealth.Value = SecurePlayerPrefs.GetInt("MaxHealth", startingHealth);
            _health.Value = SecurePlayerPrefs.GetInt("Health", startingHealth);
            _currency.Value = SecurePlayerPrefs.GetInt("Currency", startingCurrency);
            _baseDamage.Value = SecurePlayerPrefs.GetInt("BaseDamage", startingBaseDamage);
            _damageMultiplier.Value = SecurePlayerPrefs.GetFloat("DamageMultiplier", startingDamageMultiplier);
            _armorRating.Value = SecurePlayerPrefs.GetInt("ArmorRating", startingArmorRating);
            _level.Value = SecurePlayerPrefs.GetInt("Level", 1);
        }
        else
        {
            _maxHealth.Value = startingHealth;
            _health.Value = startingHealth;
            _currency.Value = startingCurrency;
            _baseDamage.Value = startingBaseDamage;
            _damageMultiplier.Value = startingDamageMultiplier;
            _armorRating.Value = startingArmorRating;
            _level.Value = 1;
        }

        // Initialize shadow copies
        _healthShadow.Value = _health.Value;
        _currencyShadow.Value = _currency.Value;
        _isDead = false;
    }

    public void SaveStats()
    {
        SecurePlayerPrefs.SetInt("HasSaveData", 1);
        SecurePlayerPrefs.SetInt("MaxHealth", _maxHealth.Value);
        SecurePlayerPrefs.SetInt("Health", _health.Value);
        SecurePlayerPrefs.SetInt("Currency", _currency.Value);
        SecurePlayerPrefs.SetInt("BaseDamage", _baseDamage.Value);
        SecurePlayerPrefs.SetFloat("DamageMultiplier", _damageMultiplier.Value);
        SecurePlayerPrefs.SetInt("ArmorRating", _armorRating.Value);
        SecurePlayerPrefs.SetInt("Level", _level.Value);
    }

    /// <summary>
    /// Apply damage to the player with validated calculation.
    /// </summary>
    public void TakeDamage(int rawDamage, DamageType damageType = DamageType.Physical)
    {
        if (_isDead) return;
        if (rawDamage < 0)
        {
            Debug.LogWarning("[SECURITY] Negative damage attempted, ignoring.");
            return;
        }

        int finalDamage = DamageCalculator.CalculateIncomingDamage(rawDamage, _armorRating.Value, damageType);

        // Validate damage is within reasonable bounds
        finalDamage = Mathf.Clamp(finalDamage, 0, rawDamage); // Can't take more than raw damage
        finalDamage = Mathf.Min(finalDamage, _health.Value); // Can't go below 0

        int newHealth = _health.Value - finalDamage;
        newHealth = Mathf.Max(0, newHealth);

        SetHealthInternal(newHealth);

        if (newHealth <= 0)
        {
            _isDead = true;
            OnPlayerDied?.Invoke();
        }
    }

    /// <summary>
    /// Heal the player by a specified amount.
    /// </summary>
    public void Heal(int amount)
    {
        if (_isDead) return;
        if (amount < 0)
        {
            Debug.LogWarning("[SECURITY] Negative heal attempted, ignoring.");
            return;
        }

        int newHealth = Mathf.Min(_health.Value + amount, _maxHealth.Value);
        SetHealthInternal(newHealth);
    }

    /// <summary>
    /// Calculate outgoing damage from this player.
    /// </summary>
    public int CalculateOutgoingDamage()
    {
        return DamageCalculator.CalculateOutgoingDamage(
            _baseDamage.Value,
            _damageMultiplier.Value,
            _level.Value
        );
    }

    /// <summary>
    /// Add currency with validation.
    /// </summary>
    public bool AddCurrency(int amount, CurrencySource source)
    {
        if (amount < 0)
        {
            Debug.LogWarning("[SECURITY] Negative currency add attempted.");
            return false;
        }

        // Validate currency gain is reasonable for the source
        if (!ValidateCurrencyGain(amount, source))
        {
            Debug.LogError($"[SECURITY] Suspicious currency gain: {amount} from {source}");
            HandleTamperDetected();
            return false;
        }

        int newCurrency = _currency.Value + amount;

        // Overflow protection
        if (newCurrency < _currency.Value)
        {
            Debug.LogError("[SECURITY] Currency overflow detected.");
            return false;
        }

        SetCurrencyInternal(newCurrency);
        return true;
    }

    /// <summary>
    /// Remove currency (for purchases). Returns false if insufficient funds.
    /// </summary>
    public bool SpendCurrency(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("[SECURITY] Negative currency spend attempted.");
            return false;
        }

        if (_currency.Value < amount)
        {
            return false;
        }

        SetCurrencyInternal(_currency.Value - amount);
        return true;
    }

    public void IncreaseMaxHealth(int amount)
    {
        if (amount <= 0) return;
        _maxHealth.Value = _maxHealth.Value + amount;
    }

    public void IncreaseDamageMultiplier(float amount)
    {
        if (amount <= 0f) return;
        float newMult = _damageMultiplier.Value + amount;
        // Cap at reasonable value
        newMult = Mathf.Min(newMult, 10f);
        _damageMultiplier.Value = newMult;
    }

    public void IncreaseBaseDamage(int amount)
    {
        if (amount <= 0) return;
        _baseDamage.Value = _baseDamage.Value + amount;
    }

    public void IncreaseArmorRating(int amount)
    {
        if (amount <= 0) return;
        _armorRating.Value = _armorRating.Value + amount;
    }

    public void LevelUp()
    {
        _level.Value = _level.Value + 1;
        _maxHealth.Value = _maxHealth.Value + 10;
        _baseDamage.Value = _baseDamage.Value + 2;
        SetHealthInternal(_maxHealth.Value); // Full heal on level up
    }

    private void SetHealthInternal(int newHealth)
    {
        _health.Value = newHealth;
        _healthShadow.Value = newHealth;
        OnHealthChanged?.Invoke(_health.Value, _maxHealth.Value);
    }

    private void SetCurrencyInternal(int newCurrency)
    {
        _currency.Value = newCurrency;
        _currencyShadow.Value = newCurrency;
        OnCurrencyChanged?.Invoke(_currency.Value);
    }

    private bool ValidateCurrencyGain(int amount, CurrencySource source)
    {
        switch (source)
        {
            case CurrencySource.EnemyDrop:
                return amount <= 100; // Max drop per enemy
            case CurrencySource.QuestReward:
                return amount <= 1000;
            case CurrencySource.LevelComplete:
                return amount <= 5000;
            case CurrencySource.IAP:
                return true; // IAP validated through store receipt
            case CurrencySource.Admin:
                return Debug.isDebugBuild;
            default:
                return false;
        }
    }

    private void PerformIntegrityCheck()
    {
        // Cross-validate shadow copies
        if (_health.Value != _healthShadow.Value)
        {
            Debug.LogError($"[SECURITY] Health integrity mismatch: {_health.Value} vs shadow {_healthShadow.Value}");
            HandleTamperDetected();
            return;
        }

        if (_currency.Value != _currencyShadow.Value)
        {
            Debug.LogError($"[SECURITY] Currency integrity mismatch: {_currency.Value} vs shadow {_currencyShadow.Value}");
            HandleTamperDetected();
            return;
        }

        // Sanity checks
        if (_health.Value > _maxHealth.Value)
        {
            Debug.LogError("[SECURITY] Health exceeds max health.");
            HandleTamperDetected();
            return;
        }

        if (_health.Value < 0 || _currency.Value < 0)
        {
            Debug.LogError("[SECURITY] Negative stat value detected.");
            HandleTamperDetected();
            return;
        }

        if (_damageMultiplier.Value > 10f || _damageMultiplier.Value < 0f)
        {
            Debug.LogError("[SECURITY] Damage multiplier out of bounds.");
            HandleTamperDetected();
        }
    }

    private void HandleTamperDetected()
    {
        Debug.LogError("[SECURITY] TAMPERING DETECTED - Resetting to last valid save.");
        OnTamperingDetected?.Invoke();

        // Reset to saved state or defaults
        LoadOrInitializeStats();
        SaveStats();
    }

    private void OnApplicationPause(bool pauseStatus)
    {
        if (pauseStatus)
        {
            SaveStats();
        }
    }

    private void OnApplicationQuit()
    {
        SaveStats();
    }
}

public enum CurrencySource
{
    EnemyDrop,
    QuestReward,
    LevelComplete,
    IAP,
    Admin
}

public enum DamageType
{
    Physical,
    Magical,
    True // Ignores armor
}

/// <summary>
/// Deterministic damage calculator with validation.
/// </summary>
public static class DamageCalculator
{
    // Constants defined here to prevent easy modification
    private const float ARMOR_REDUCTION_FACTOR = 0.005f;
    private const float MAX_ARMOR_REDUCTION = 0.75f;
    private const float LEVEL_DAMAGE_BONUS = 0.02f;
    private const int MAX_REASONABLE_DAMAGE = 99999;

    /// <summary>
    /// Calculate damage taken after armor reduction.
    /// </summary>
    public static int CalculateIncomingDamage(int rawDamage, int armorRating, DamageType damageType)
    {
        if (rawDamage <= 0) return 0;
        if (rawDamage > MAX_REASONABLE_DAMAGE)
        {
            Debug.LogWarning("[SECURITY] Unreasonably high damage value detected.");
            rawDamage = MAX_REASONABLE_DAMAGE;
        }

        if (damageType == DamageType.True)
        {
            return rawDamage;
        }

        float armorReduction = 0f;
        if (damageType == DamageType.Physical)
        {
            armorReduction = Mathf.Min(armorRating * ARMOR_REDUCTION_FACTOR, MAX_ARMOR_REDUCTION);
        }
        else if (damageType == DamageType.Magical)
        {
            // Magical damage gets half armor reduction
            armorReduction = Mathf.Min(armorRating * ARMOR_REDUCTION_FACTOR * 0.5f, MAX_ARMOR_REDUCTION * 0.5f);
        }

        int finalDamage = Mathf.RoundToInt(rawDamage * (1f - armorReduction));
        return Mathf.Max(1, finalDamage); // Minimum 1 damage
    }

    /// <summary>
    /// Calculate outgoing damage from player stats.
    /// </summary>
    public static int CalculateOutgoingDamage(int baseDamage, float damageMultiplier, int level)
    {
        if (baseDamage < 0 || damageMultiplier < 0 || level < 1)
        {
            Debug.LogWarning("[SECURITY] Invalid damage calculation parameters.");
            return 0;
        }

        float levelBonus = 1f + (level - 1) * LEVEL_DAMAGE_BONUS;
        int finalDamage = Mathf.RoundToInt(baseDamage * damageMultiplier * levelBonus);

        // Validate result
        int expectedMax = Mathf.RoundToInt(baseDamage * 10f * (1f + 100 * LEVEL_DAMAGE_BONUS));
        if (finalDamage > expectedMax)
        {
            Debug.LogWarning("[SECURITY] Damage calculation result exceeds expected maximum.");
            return baseDamage;
        }

        return Mathf.Max(1, finalDamage);
    }

    /// <summary>
    /// Validate a damage calculation result by recomputing it.
    /// </summary>
    public static bool ValidateDamageResult(int rawDamage, int armorRating, DamageType damageType, int claimedResult)
    {
        int expected = CalculateIncomingDamage(rawDamage, armorRating, damageType);
        return expected == claimedResult;
    }
}

/// <summary>
/// Shop system with price validation and secure transactions.
/// </summary>
public class ShopManager : MonoBehaviour
{
    public static ShopManager Instance { get; private set; }

    [SerializeField] private ShopItemData[] shopItems;

    // Transaction log for auditing
    private System.Collections.Generic.List<TransactionRecord> _transactionLog =
        new System.Collections.Generic.List<TransactionRecord>();

    public event Action<ShopItemData, bool> OnPurchaseAttempted; // item, success

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }
        Instance = this;
    }

    /// <summary>
    /// Get the validated price for an item, considering any discounts.
    /// </summary>
    public int GetItemPrice(ShopItemData item)
    {
        if (item == null) return int.MaxValue;
        return ValidateAndGetPrice(item);
    }

    /// <summary>
    /// Attempt to purchase an item.
    /// </summary>
    public bool PurchaseItem(ShopItemData item)
    {
        if (item == null)
        {
            Debug.LogWarning("Attempted to purchase null item.");
            return false;
        }

        if (item.isIAP)
        {
            Debug.Log("IAP items must be purchased through the IAP system.");
            return false;
        }

        int price = ValidateAndGetPrice(item);

        if (PlayerStats.Instance.Currency < price)
        {
            Debug.Log($"Insufficient currency. Need {price}, have {PlayerStats.Instance.Currency}");
            OnPurchaseAttempted?.Invoke(item, false);
            return false;
        }

        // Atomic transaction: spend currency then apply effect
        if (!PlayerStats.Instance.SpendCurrency(price))
        {
            OnPurchaseAttempted?.Invoke(item, false);
            return false;
        }

        bool effectApplied = ApplyItemEffect(item);

        if (!effectApplied)
        {
            // Refund on failure
            PlayerStats.Instance.AddCurrency(price, CurrencySource.Admin);
            Debug.LogError($"Failed to apply item effect for {item.displayName}, refunding.");
            OnPurchaseAttempted?.Invoke(item, false);
            return false;
        }

        // Log transaction
        LogTransaction(item, price);

        OnPurchaseAttempted?.Invoke(item, true);
        PlayerStats.Instance.SaveStats();

        Debug.Log($"Successfully purchased {item.displayName} for {price} currency.");
        return true;
    }

    /// <summary>
    /// Handle IAP purchase completion (called after store validates receipt).
    /// </summary>
    public void OnIAPPurchaseCompleted(string productId)
    {
        ShopItemData item = FindItemByIAPId(productId);
        if (item == null)
        {
            Debug.LogError($"Unknown IAP product: {productId}");
            return;
        }

        ApplyItemEffect(item);
        LogTransaction(item, 0); // Price 0 since it was real money
        PlayerStats.Instance.SaveStats();
    }

    /// <summary>
    /// Validate price using the item's seed to prevent price manipulation.
    /// </summary>
    private int ValidateAndGetPrice(ShopItemData item)
    {
        // Recompute price from immutable ScriptableObject data
        // This prevents memory editing of the price
        int computedPrice = item.basePrice;

        // Validate using seed
        int expectedCheck = (item.basePrice * item.priceValidationSeed) % 10000;
        int actualCheck = (computedPrice * item.priceValidationSeed) % 10000;

        if (expectedCheck != actualCheck)
        {
            Debug.LogError($"[SECURITY] Price validation failed for {item.displayName}");
            return int.MaxValue; // Return impossibly high price
        }

        return Mathf.Max(1, computedPrice);
    }

    private bool ApplyItemEffect(ShopItemData item)
    {
        var player = PlayerStats.Instance;
        if (player == null) return false;

        switch (item.itemType)
        {
            case ShopItemType.HealthPotion:
                player.Heal(item.effectValue);
                return true;

            case ShopItemType.DamageBoost:
                player.IncreaseDamageMultiplier(item.effectValue * 0.1f);
                return true;

            case ShopItemType.Armor:
                player.IncreaseArmorRating(item.effectValue);
                return true;

            case ShopItemType.Weapon:
                player.IncreaseBaseDamage(item.effectValue);
                return true;

            case ShopItemType.CurrencyPack:
                player.AddCurrency(item.effectValue, CurrencySource.IAP);
                return true;

            default:
                Debug.LogWarning($"Unknown item type: {item.itemType}");
                return false;
        }
    }

    private ShopItemData FindItemByIAPId(string productId)
    {
        if (shopItems == null) return null;
        foreach (var item in shopItems)
        {
            if (item.isIAP && item.iapProductId == productId)
                return item;
        }
        return null;
    }

    private void LogTransaction(ShopItemData item, int price)
    {
        var record = new TransactionRecord
        {
            itemId = item.itemId,
            price = price,
            timestamp = DateTime.UtcNow.Ticks,
            currencyAfter = PlayerStats.Instance.Currency
        };

        _transactionLog.Add(record);

        // Keep only last 100 transactions in memory
        if (_transactionLog.Count > 100)
        {
            _transactionLog.RemoveAt(0);
        }

        // Persist transaction hash for validation
        string transactionData = $"{record.itemId}:{record.price}:{record.timestamp}:{record.currencyAfter}";
        SecurePlayerPrefs.SetString("LastTransaction", transactionData);
    }

    /// <summary>
    /// Check if player can afford an item.
    /// </summary>
    public bool CanAfford(ShopItemData item)
    {
        if (item == null) return false;
        return PlayerStats.Instance.Currency >= GetItemPrice(item);
    }
}

[Serializable]
public struct TransactionRecord
{
    public string itemId;
    public int price;
    public long timestamp;
    public int currencyAfter;
}

/// <summary>
/// Runtime anti-cheat monitor that performs periodic checks.
/// </summary>
public class AntiCheatMonitor : MonoBehaviour
{
    public static AntiCheatMonitor Instance { get; private set; }

    [SerializeField] private float speedHackCheckInterval = 1f;

    private float _lastRealTime;
    private float _lastGameTime;
    private int _violationCount;
    private const int MAX_VIOLATIONS = 3;
    private const float SPEED_HACK_THRESHOLD = 1.5f; // Allow 50% variance

    public event Action OnCheatDetected;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }
        Instance = this;
        DontDestroyOnLoad(gameObject);

        _lastRealTime = Time.realtimeSinceStartup;
        _lastGameTime = Time.time;
    }

    private void Update()
    {
        CheckSpeedHack();
    }

    /// <summary>
    /// Detect time manipulation (speed hacks).
    /// </summary>
    private void CheckSpeedHack()
    {
        float currentRealTime = Time.realtimeSinceStartup;
        float realTimeDelta = currentRealTime - _lastRealTime;

        if (realTimeDelta >= speedHackCheckInterval)
        {
            float gameTimeDelta = Time.time - _lastGameTime;
            float ratio = gameTimeDelta / realTimeDelta;

            if (ratio > SPEED_HACK_THRESHOLD)
            {
                _violationCount++;
                Debug.LogWarning($"[ANTI-CHEAT] Speed hack suspected. Ratio: {ratio:F2}, Violations: {_violationCount}");

                if (_violationCount >= MAX_VIOLATIONS)
                {
                    Debug.LogError("[ANTI-CHEAT] Speed hack confirmed!");
                    Time.timeScale = 1f;
                    OnCheatDetected?.Invoke();
                    _violationCount = 0;
                }
            }
            else
            {
                // Decay violations over time
                _violationCount = Mathf.Max(0, _violationCount - 1);
            }

            _lastRealTime = currentRealTime;
            _lastGameTime = Time.time;
        }
    }

    /// <summary>
    /// Validate that a gameplay event is plausible.
    /// Call this when enemies are killed, loot is gained, etc.
    /// </summary>
    public bool ValidateGameplayEvent(string eventType, float expectedMinInterval)
    {
        string key = "LastEvent_" + eventType;
        float lastEventTime = SecurePlayerPrefs.GetFloat(key, 0f);
        float currentTime = Time.realtimeSinceStartup;

        if (currentTime - lastEventTime < expectedMinInterval)
        {
            Debug.LogWarning($"[ANTI-CHEAT] Event '{eventType}' happening too fast.");
            return false;
        }

        SecurePlayerPrefs.SetFloat(key, currentTime);
        return true;
    }
}

/// <summary>
/// Example combat controller showing how to use the secure systems.
/// </summary>
public class CombatController : MonoBehaviour
{
    [SerializeField] private int enemyBaseDamage = 15;
    [SerializeField] private int enemyHealth = 50;
    [SerializeField] private int currencyRewardMin = 5;
    [SerializeField] private int currencyRewardMax = 20;

    private SecureInt _currentEnemyHealth;

    private void Start()
    {
        _currentEnemyHealth.Value = enemyHealth;
    }

    /// <summary>
    /// Player attacks enemy.
    /// </summary>
    public void PlayerAttackEnemy()
    {
        if (PlayerStats.Instance == null) return;

        int damage = PlayerStats.Instance.CalculateOutgoingDamage();
        _currentEnemyHealth.Value = Mathf.Max(0, _currentEnemyHealth.Value - damage);

        Debug.Log($"Player dealt {damage} damage. Enemy HP: {_currentEnemyHealth.Value}");

        if (_currentEnemyHealth.Value <= 0)
        {
            OnEnemyDefeated();
        }
    }

    /// <summary>
    /// Enemy attacks player.
    /// </summary>
    public void EnemyAttackPlayer()
    {
        if (PlayerStats.Instance == null) return;

        PlayerStats.Instance.TakeDamage(enemyBaseDamage, DamageType.Physical);
        Debug.Log($"Enemy dealt {enemyBaseDamage} raw damage. Player HP: {PlayerStats.Instance.Health}");
    }

    private void OnEnemyDefeated()
    {
        // Validate this kill event is plausible
        if (AntiCheatMonitor.Instance != null &&
            !AntiCheatMonitor.Instance.ValidateGameplayEvent("EnemyKill", 0.5f))
        {
            Debug.LogWarning("Kill event rejected by anti-cheat.");
            return;
        }

        int reward = UnityEngine.Random.Range(currencyRewardMin, currencyRewardMax + 1);
        PlayerStats.Instance.AddCurrency(reward, CurrencySource.EnemyDrop);

        Debug.Log($"Enemy defeated! Earned {reward} currency.");

        // Reset enemy
        _currentEnemyHealth.Value = enemyHealth;
    }
}